import sys, os, math, random, base64, tempfile, shutil, subprocess, atexit
from PyQt6.QtWidgets import (QApplication, QWidget, QVBoxLayout, QHBoxLayout, QLabel, QLineEdit,
                             QPushButton, QTextEdit, QComboBox, QFrame, QMessageBox)
from PyQt6.QtGui import QFont, QIcon
from PyQt6.QtCore import Qt, QTimer

# --- INCOLLA QUI IL TUO CODICE BASE64 ---
BASE64_XM = r"""""" 

try:
    import pygame
    PYGAME_AVAILABLE = True
except Exception:
    PYGAME_AVAILABLE = False
    
def resource_path(relative_path):
    try:
        base_path = sys._MEIPASS
    except Exception:
        base_path = os.path.abspath(".")
    return os.path.join(base_path, relative_path)
    
class CarAudioEnergyAnalyzerV6(QWidget):
    def __init__(self):
        super().__init__()
        self.setWindowIcon(QIcon(resource_path("icongg.ico")))
        self.setWindowTitle("BAT")
        self.resize(1150, 950)
        self.setStyleSheet("background-color: black; color: #00ff41; font-family: 'Consolas', monospace;")
        
        self.NEON_GREEN = "#00ff41"
        self.NEON_GREEN_DIM = "#008021"
        self.NEON_PURPLE = "#B200FF"

        self.music_on = False # Inizialmente false, verrà attivata da toggle_music()
        self.music_temp_path = None
        self.music_wav_path = None

        self.build_ui()
        self.prepare_music()
        
        # ATTIVAZIONE AUTOMATICA
        if PYGAME_AVAILABLE:
            self.toggle_music()

        self.timer = QTimer()
        self.timer.timeout.connect(self.neon_pulse)
        self.timer.start(500)
        
        atexit.register(self.cleanup)

    def build_ui(self):
        layout = QVBoxLayout(self)
        layout.setSpacing(0)

        # LOGO ASCII - Gestito con tag <pre> per precisione millimetrica
        logo_content = r"""fontfontfont$fontfontfont$font            font$fontfontfontfont$fontfontfont    $        font        $fontfontfont$fontfontfont$fontfontfontfont$fontfontfont    $font    font$
    font    $    font    $fontfont    fontfont$font            $font    fontfont$      fontfont      $    font    $    font    $font            $font    fontfont$font    font$
    font    $    font    $fontfontfontfontfont$font            $font        font$    fontfontfont    $    font    $    font    $font            $font    fontfont$font    font$
    font    $    font    $font    font    font$font            $font        font$  font        font  $    font    $    font    $font            $fontfontfont    $fontfontfont$
    font    $    font    $font            font$fontfontfontfont$fontfontfontfont$fontfontfontfontfont$    font    $    font    $fontfontfontfont$font    fontfont$    font    $
    font    $    font    $font            font$font            $font        font$font            font$    font    $    font    $font            $font        font$    font    $
    font    $    font    $font            font$font            $font        font$font            font$    font    $    font    $font            $font        font$    font    $
    font    $    font    $font            font$font            $font    fontfont$font            font$    font    $    font    $font            $font        font$    font    $
    font    $fontfontfont$font            font$fontfontfontfont$fontfontfont    $font            font$    font    $    font    $fontfontfontfont$font        font$    font    $
            $            $                    $                $                $                    $            $            $                $                $            $
            $            $                    $                $                $                    $            $            $                $                $            $"""

        self.logo_label = QLabel(f"<pre style='line-height:1; font-family:Consolas, monospace; font-size:7pt;'>{logo_content}</pre>")
        self.logo_label.setAlignment(Qt.AlignmentFlag.AlignCenter)
        self.logo_label.setStyleSheet(f"color: {self.NEON_GREEN}; margin: 0px; padding: 0px;")
        layout.addWidget(self.logo_label)

        sub_logo = QLabel("-- by Obscurio51 --")
        sub_logo.setAlignment(Qt.AlignmentFlag.AlignCenter)
        sub_logo.setStyleSheet(f"color: {self.NEON_PURPLE}; font-weight: bold; margin-bottom: 10px;")
        layout.addWidget(sub_logo)

        content = QHBoxLayout()
        layout.addLayout(content)

        # --- SINISTRA: INPUT ---
        input_frame = QFrame()
        input_frame.setStyleSheet(f"border: 2px solid {self.NEON_GREEN_DIM}; border-radius: 10px; background-color: #050505;")
        input_layout = QVBoxLayout(input_frame)
        input_layout.setContentsMargins(20, 20, 20, 20)
        input_layout.setSpacing(10)
        content.addWidget(input_frame, 1)

        input_layout.addWidget(self.make_label("POTENZA ALTERNATORE (A):"))
        self.entry_alt = self.make_styled_input("90")
        input_layout.addWidget(self.entry_alt)

        input_layout.addWidget(self.make_label("SOMMA FUSIBILI AMPLIFICATORI (A):"))
        self.entry_fuses = self.make_styled_input("120")
        input_layout.addWidget(self.entry_fuses)

        input_layout.addWidget(self.make_label("GENERE MUSICALE / CARICO:"))
        self.combo_factor = QComboBox()
        self.combo_factor.addItems(["Ascolto Leggero (20%)", "Ascolto Moderato (30%)", "(40%)", "Ascolto Intenso (50%)", "(60%)", "(70%)", "(80%)", "SPL (100%)"])
        self.combo_factor.setCurrentIndex(1)
        self.style_combo(self.combo_factor)
        input_layout.addWidget(self.combo_factor)

        input_layout.addWidget(self.make_label("CAPACITÀ CONDENSATORE (FARAD):"))
        self.entry_farad = self.make_styled_input("2.0")
        input_layout.addWidget(self.entry_farad)

        input_layout.addWidget(self.make_label("MINUTI ASCOLTO (MOTORE SPENTO):"))
        self.entry_time = self.make_styled_input("60")
        input_layout.addWidget(self.entry_time)

        input_layout.addWidget(self.make_label("TECNOLOGIA BATTERIA:"))
        self.combo_bat_type = QComboBox()
        self.combo_bat_type.addItems(["Piombo (DoD 30%)", "AGM (DoD 50%)", "Gel (DoD 60%)", "AGM Competition (DoD 70%)", "LiFePO4 (DoD 90%)", "LTO (DoD 95%)"])
        self.combo_bat_type.setCurrentIndex(1)
        self.style_combo(self.combo_bat_type)
        input_layout.addWidget(self.combo_bat_type)

        input_layout.addStretch()
        
        self.btn_calc = self.make_btn(">>> ANALIZZA <<<", self.calculate, self.NEON_GREEN)
        input_layout.addWidget(self.btn_calc)
        
        # Inizializzato come OFF, ma cambierà subito grazie alla chiamata in __init__
        self.btn_music = self.make_btn("MUSIC: OFF", self.toggle_music, self.NEON_PURPLE)
        input_layout.addWidget(self.btn_music)

        # --- DESTRA: RISULTATI ---
        output_frame = QFrame()
        output_layout = QVBoxLayout(output_frame)
        content.addWidget(output_frame, 1)

        output_layout.addWidget(self.make_label("Ah BATTERIA CONSIGLIATI:"))
        self.lbl_res_ah = QLabel("0.0")
        self.lbl_res_ah.setAlignment(Qt.AlignmentFlag.AlignCenter)
        self.lbl_res_ah.setStyleSheet(f"background-color: #001100; color: {self.NEON_GREEN}; border: 4px solid {self.NEON_GREEN}; font-size: 60pt; font-weight: bold; border-radius: 15px;")
        output_layout.addWidget(self.lbl_res_ah)

        output_layout.addWidget(self.make_label("REPORT TECNICO ALTERNATORE E SISTEMA:"))
        self.text_log = QTextEdit()
        self.text_log.setReadOnly(True)
        self.text_log.setStyleSheet(f"background-color: #000800; color: {self.NEON_GREEN_DIM}; border: 1px solid {self.NEON_GREEN_DIM}; font-size: 10pt;")
        output_layout.addWidget(self.text_log)

    # (UI HELPERS) ...
    def make_label(self, text):
        l = QLabel(text)
        l.setStyleSheet(f"color: {self.NEON_GREEN}; font-weight: bold; font-size: 9pt;")
        return l

    def make_styled_input(self, default):
        e = QLineEdit()
        e.setText(default)
        e.setAlignment(Qt.AlignmentFlag.AlignCenter)
        e.setStyleSheet(f"background-color: #001100; color: {self.NEON_GREEN}; border: 1px solid #008021; border-radius: 4px; padding: 8px; font-size: 14pt; font-weight: bold;")
        return e

    def style_combo(self, combo):
        combo.setStyleSheet(f"background-color: #001100; color: {self.NEON_GREEN}; border: 1px solid #008021; border-radius: 4px; padding: 5px; font-size: 11pt;")

    def make_btn(self, text, func, color):
        b = QPushButton(text)
        b.setFont(QFont("Consolas", 11, QFont.Weight.Bold))
        b.clicked.connect(func)
        b.setCursor(Qt.CursorShape.PointingHandCursor)
        b.setStyleSheet(f"QPushButton {{ background-color: #001100; color: {color}; border: 2px solid {color}; padding: 12px; border-radius: 5px; }} QPushButton:hover {{ background-color: {color}; color: black; }}")
        return b

    def neon_pulse(self):
        color = self.NEON_GREEN if random.random() > 0.1 else self.NEON_GREEN_DIM
        self.logo_label.setStyleSheet(f"color: {color};")

    # (CALCOLO) ...
    def calculate(self):
        try:
            alt_amps = float(self.entry_alt.text().replace(",", "."))
            fuses = float(self.entry_fuses.text().replace(",", "."))
            farads = float(self.entry_farad.text().replace(",", "."))
            minutes = float(self.entry_time.text().replace(",", "."))
            factor_percent = float(self.combo_factor.currentText().split("(")[1].split("%")[0]) / 100.0
            bat_text = self.combo_bat_type.currentText()
            dod_percent = float(bat_text.split("DoD ")[1].split("%")[0]) / 100.0
            base_draw = fuses * factor_percent
            est_watts = base_draw * 13.5
            base_threshold = est_watts / 1000.0
            efficiency_bonus = 0
            if farads >= (base_threshold * 2) and farads > 0: efficiency_bonus = 0.15 
            elif farads >= base_threshold and farads > 0: efficiency_bonus = 0.10 
            final_draw = base_draw * (1 - efficiency_bonus)
            car_overhead = 20.0
            net_alternator = alt_amps - car_overhead
            balance = net_alternator - final_draw
            hours = minutes / 60.0
            theoretical_ah = final_draw * hours
            required_ah = theoretical_ah / dod_percent
            report = f"--- ANALISI ENERGETICA V6 ---\nAssorbimento reale: {final_draw:.2f} A\n------------------------------------\nRESOCONTO ALTERNATORE:\nErogazione Disponibile -20A Servizi: {net_alternator:.2f} A\n"
            if balance > 0: report += f"STATUS: [ OK ]\nMargine ricarica: +{balance:.2f} A\n"
            else: report += f"STATUS: [ CRITICO ]\nScarica in moto: {abs(balance):.2f} A\n"
            report += f"------------------------------------\nAUTONOMIA MOTORE SPENTO:\nEnergia prelevata: {theoretical_ah:.2f} Ah\nCapacità richiesta: {required_ah:.1f} Ah"
            self.lbl_res_ah.setText(f"{required_ah:.1f}")
            self.text_log.setPlainText(report)
        except: QMessageBox.critical(self, "Errore", "Verifica i dati!")

    # --- LOGICA MUSICA ---
    def prepare_music(self):
        if not BASE64_XM: return
        try:
            raw = base64.b64decode(BASE64_XM)
            fd, temp_path = tempfile.mkstemp(prefix="audio_", suffix=".xm")
            os.close(fd)
            with open(temp_path, "wb") as f: f.write(raw)
            self.music_temp_path = temp_path
            if shutil.which("ffmpeg"):
                fd, wav_path = tempfile.mkstemp(prefix="audio_", suffix=".wav")
                os.close(fd)
                subprocess.run(["ffmpeg", "-y", "-i", self.music_temp_path, wav_path], stdout=subprocess.PIPE, stderr=subprocess.PIPE)
                self.music_wav_path = wav_path
        except: pass

    def toggle_music(self):
        if not PYGAME_AVAILABLE or not BASE64_XM: return
        if self.music_on:
            pygame.mixer.music.stop()
            self.btn_music.setText("MUSIC: OFF")
            self.music_on = False
        else:
            try:
                if not pygame.mixer.get_init(): pygame.mixer.init()
                pygame.mixer.music.load(self.music_wav_path or self.music_temp_path)
                pygame.mixer.music.play(-1)
                self.btn_music.setText("MUSIC: ON")
                self.music_on = True
            except: pass

    def cleanup(self):
        if PYGAME_AVAILABLE:
            try: pygame.mixer.music.stop()
            except: pass
        for f in [self.music_temp_path, self.music_wav_path]:
            if f and os.path.exists(f):
                try: os.remove(f)
                except: pass

if __name__ == "__main__":
    app = QApplication(sys.argv)
    win = CarAudioEnergyAnalyzerV6()
    win.show()
    sys.exit(app.exec())